#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_LENGTH 100

// Structure for fixed-length string representation
typedef struct {
 char ch[MAX_LENGTH];
 int length;
} FixedString;

// Structure for dynamic string representation
typedef struct {
 char *ch; // dynamically allocated
 int length; // current string length
 int capacity; // allocated capacity
} DynString;

// ============================================
// FIXED-LENGTH STRING OPERATIONS
// ============================================

// O(n) - Compute string length by scanning until null terminator
int strLen(const char *s) {
 int count = 0;
 while (s[count] != '\0') {
 count++;
 }
 return count;
}

// O(n) - Copy source string to destination
void strCopy(char *dest, const char *src) {
 int i = 0;
 while (src[i] != '\0') {
 dest[i] = src[i];
 i++;
 }
 dest[i] = '\0'; // Don't forget null terminator!
}

// O(min(n, m)) - Compare strings lexicographically
int strCompare(const char *s, const char *t) {
 int i = 0;
 while (s[i] != '\0' && t[i] != '\0') {
 if (s[i] != t[i]) {
 return (int)s[i] - (int)t[i]; // Return difference
 }
 i++;
 }
 return (int)s[i] - (int)t[i]; // Handle length difference
}

// O(n + m) - Concatenate source to end of destination
void strConcat(char *dest, const char *src) {
 int i = strLen(dest);
 int j = 0;
 while (src[j] != '\0') {
 dest[i] = src[j];
 i++;
 j++;
 }
 dest[i] = '\0';
}

// O(j) - Extract substring of length j starting at position i
void subStr(const char *s, int i, int j, char *result) {
 int k;
 for (k = 0; k < j && s[i + k] != '\0'; k++) {
 result[k] = s[i + k];
 }
 result[k] = '\0';
}

// O(n + m) - Insert string t at position pos in s
void strInsert(char *s, int pos, const char *t) {
 int sLen = strLen(s);
 int tLen = strLen(t);

 // Check bounds
 if (pos < 0 || pos > sLen) return;

 // Shift characters from pos to right by tLen positions
 for (int i = sLen; i >= pos; i--) {
 s[i + tLen] = s[i];
 }

 // Copy t into the gap
 for (int i = 0; i < tLen; i++) {
 s[pos + i] = t[i];
 }
}

// O(n) - Delete j characters starting at position pos
void strDelete(char *s, int pos, int j) {
 int sLen = strLen(s);

 if (pos < 0 || pos >= sLen || j <= 0) return;

 // Shift characters from pos+j to left by j positions
 for (int i = pos; i < sLen - j; i++) {
 s[i] = s[i + j];
 }
 s[sLen - j] = '\0';
}

// ============================================
// DYNAMIC STRING OPERATIONS
// ============================================

// Create and initialize dynamic string
DynString* createString(const char *init) {
 DynString *s = (DynString*)malloc(sizeof(DynString));
 s->length = strlen(init);
 s->capacity = s->length + 1; // +1 for null terminator
 s->ch = (char*)malloc(s->capacity * sizeof(char));
 strcpy(s->ch, init);
 return s;
}

// Free dynamic string memory
void freeString(DynString *s) {
 if (s != NULL) {
 free(s->ch);
 free(s);
 }
}

// Dynamic string concatenation with reallocation
void dynConcat(DynString *s, const char *t) {
 int tLen = strlen(t);
 int newLength = s->length + tLen;

 // Check if reallocation needed
 if (newLength + 1 > s->capacity) {
 s->capacity = newLength + 1;
 s->ch = (char*)realloc(s->ch, s->capacity * sizeof(char));
 }

 strcat(s->ch, t);
 s->length = newLength;
}

// ============================================
// NAIVE PATTERN MATCHING
// ============================================

// O(n * m) - Find pattern in text, return position or -1
int naivePatternMatch(const char *text, const char *pattern) {
 int n = strlen(text);
 int m = strlen(pattern);

 if (m > n) return -1;

 for (int i = 0; i <= n - m; i++) {
 int j;
 for (j = 0; j < m; j++) {
 if (text[i + j] != pattern[j]) {
 break; // Mismatch found
 }
 }
 if (j == m) {
 return i; // Complete match found
 }
 }
 return -1; // No match
}

// ============================================
// MAIN - DEMONSTRATION
// ============================================

int main() {
 char buffer[MAX_LENGTH];

 printf("=== C String Operations Demo ===\n\n");

 // StrLen demo
 printf("StrLen(\"DATA\"): %d\n", strLen("DATA"));

 // StrCopy demo
 strCopy(buffer, "HELLO");
 printf("StrCopy result: %s\n", buffer);

 // StrCompare demo
 printf("StrCompare(\"ABC\", \"ABD\"): %d\n", strCompare("ABC", "ABD"));
 printf("StrCompare(\"ABC\", \"ABC\"): %d\n", strCompare("ABC", "ABC"));

 // StrConcat demo
 strCopy(buffer, "DATA");
 strConcat(buffer, "STRUCTURE");
 printf("StrConcat result: %s\n", buffer);

 // SubStr demo
 strCopy(buffer, "HELLO WORLD");
 char subBuffer[20];
 subStr(buffer, 6, 5, subBuffer);
 printf("SubStr(\"HELLO WORLD\", 6, 5): %s\n", subBuffer);

 // StrInsert demo
 strCopy(buffer, "ACE");
 strInsert(buffer, 1, "B");
 printf("StrInsert(\"ACE\", 1, \"B\"): %s\n", buffer);

 // StrDelete demo
 strCopy(buffer, "ABCDE");
 strDelete(buffer, 1, 2);
 printf("StrDelete(\"ABCDE\", 1, 2): %s\n", buffer);

 // Pattern Matching demo
 int pos = naivePatternMatch("ABCABCABCD", "ABCD");
 printf("Pattern 'ABCD' found at position: %d\n", pos);

 // Dynamic string demo
 printf("\n=== Dynamic String Demo ===\n");
 DynString *dynStr = createString("Hello");
 printf("Initial: %s (len=%d, cap=%d)\n", dynStr->ch, dynStr->length, dynStr->capacity);

 dynConcat(dynStr, " World!");
 printf("After concat: %s (len=%d, cap=%d)\n", dynStr->ch, dynStr->length, dynStr->capacity);

 freeString(dynStr);

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* ============================================
 KMP (KNUTH-MORRIS-PRATT) ALGORITHM

 Time Complexity: O(n + m)
 Space Complexity: O(m)
 ============================================ */

// Compute the Failure Function (Prefix Function)
// failure[i] = length of longest proper prefix that is also suffix
// in pattern[0..i]
// 
// Example: pattern = "ABABAC"
// failure[] = [0, 0, 1, 2, 3, 0]
// 
// Pattern: A B A B A C
// Index: 0 1 2 3 4 5
// Failure: 0 0 1 2 3 0

void computeFailureFunction(const char *pattern, int m, int *failure) {
 failure[0] = 0; // First character has no proper prefix

 int i = 1; // current position in pattern
 int len = 0; // length of current matching prefix

 while (i < m) {
 if (pattern[i] == pattern[len]) {
 // Characters match, extend the prefix length
 len++;
 failure[i] = len;
 i++;
 } else {
 // Characters don't match
 if (len != 0) {
 // Try shorter prefix using failure function
 len = failure[len - 1];
 // Note: don't increment i here
 } else {
 // No prefix matches
 failure[i] = 0;
 i++;
 }
 }
 }
}

// KMP Pattern Matching Algorithm
// Returns the starting position of first match, or -1 if not found
int kmpSearch(const char *text, const char *pattern) {
 int n = strlen(text);
 int m = strlen(pattern);

 if (m == 0) return 0; // Empty pattern matches at position 0
 if (n < m) return -1; // Pattern longer than text

 // Allocate failure array
 int *failure = (int*)malloc(m * sizeof(int));

 // Step 1: Preprocess pattern to compute failure function
 computeFailureFunction(pattern, m, failure);

 // Print failure function for visualization
 printf("Failure Function for '%s': ", pattern);
 for (int i = 0; i < m; i++) {
 printf("[%d]=%d ", i, failure[i]);
 }
 printf("\n");

 // Step 2: Search through text using failure function
 int i = 0; // index for text
 int j = 0; // index for pattern

 while (i < n) {
 if (pattern[j] == text[i]) {
 // Characters match, move to next characters
 j++;
 i++;

 if (j == m) {
 // Complete match found!
 free(failure);
 return i - j; // Return starting position
 }
 } else {
 // Mismatch occurred
 if (j != 0) {
 // Use failure function to skip redundant comparisons
 j = failure[j - 1];
 } else {
 // No prefix match, move to next text character
 i++;
 }
 }
 }

 free(failure);
 return -1; // No match found
}

// Trace KMP algorithm step by step
void kmpTrace(const char *text, const char *pattern) {
 int n = strlen(text);
 int m = strlen(pattern);

 int *failure = (int*)malloc(m * sizeof(int));
 computeFailureFunction(pattern, m, failure);

 printf("\n=== KMP Trace ===\n");
 printf("Text: '%s' (length %d)\n", text, n);
 printf("Pattern: '%s' (length %d)\n\n", pattern, m);

 int i = 0, j = 0;
 int step = 1;

 while (i < n) {
 printf("Step %d: text[%d]='%c' vs pattern[%d]='%c' ", 
 step++, i, text[i], j, pattern[j]);

 if (pattern[j] == text[i]) {
 printf("=> MATCH, advancing\n");
 j++;
 i++;

 if (j == m) {
 printf("\n>>> MATCH FOUND at position %d! <<<\n", i - j);
 break;
 }
 } else {
 if (j != 0) {
 printf("=> MISMATCH, j jumps from %d to %d (failure[%d])\n",
 j, failure[j-1], j-1);
 j = failure[j - 1];
 } else {
 printf("=> MISMATCH, advancing text index\n");
 i++;
 }
 }
 }

 if (j != m && i >= n) {
 printf("\n>>> NO MATCH FOUND <<<\n");
 }

 free(failure);
}

// ============================================
// MAIN - DEMONSTRATION
// ============================================

int main() {
 printf("=== KMP Pattern Matching Algorithm ===\n\n");

 // Example 1: Simple pattern match
 const char *text1 = "ABCABCABCD";
 const char *pattern1 = "ABCD";

 printf("Example 1:\n");
 printf("Text: '%s'\n", text1);
 printf("Pattern: '%s'\n", pattern1);
 int result = kmpSearch(text1, pattern1);
 printf("Result: Pattern found at position %d\n\n", result);

 // Example 2: Trace the algorithm
 const char *text2 = "ABABDABACDABABCABAB";
 const char *pattern2 = "ABABCABAB";

 printf("Example 2:\n");
 kmpTrace(text2, pattern2);

 // Example 3: No match case
 const char *text3 = "HELLO WORLD";
 const char *pattern3 = "XYZ";

 printf("\n\nExample 3 (No Match):\n");
 printf("Text: '%s'\n", text3);
 printf("Pattern: '%s'\n", pattern3);
 result = kmpSearch(text3, pattern3);
 printf("Result: %d (not found)\n", result);

 // Example 4: Repeated characters
 const char *text4 = "AAAAAAAB";
 const char *pattern4 = "AAA";

 printf("\n\nExample 4 (Repeated Characters):\n");
 printf("Text: '%s'\n", text4);
 printf("Pattern: '%s'\n", pattern4);
 result = kmpSearch(text4, pattern4);
 printf("Result: Pattern found at position %d\n", result);

 return 0;
}
